func swapping(x: inout Int, y: inout Int) {
    let temp = x
    x = y
    y = temp
}

var num1 = 20
var num2 = 60

print("Before the numbers are swapped: \(num1) and \(num2)")

swapping(x: &num1, y: &num2)

print("After the numbers are swapped: \(num1) and \(num2)")

// Output:
// Before the numbers are swapped: 20 and 60
// After the numbers are swapped: 60 and 20

```
